import mongoose from 'mongoose';
import dotenv from 'dotenv';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
dotenv.config({ path: path.resolve(__dirname, '../.env.local') });
dotenv.config({ path: path.resolve(__dirname, '../.env') });

const MONGO_URI = process.env.MONGO_URI;
if (!MONGO_URI) { console.error('MONGO_URI not found'); process.exit(1); }

const examCategorySchema = new mongoose.Schema({
  name: { type: String, required: true, trim: true },
  type: { type: String, enum: ['Central', 'State'], required: true },
  description: { type: String, trim: true }
}, { timestamps: true });

const examSchema = new mongoose.Schema({
  category: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamCategory', required: true },
  name: { type: String, required: true, trim: true },
  code: { type: String, required: true, uppercase: true, trim: true },
  description: { type: String, trim: true },
  isActive: { type: Boolean, default: true },
  logo: { type: String }
}, { timestamps: true });

const examPatternSchema = new mongoose.Schema({
  exam: { type: mongoose.Schema.Types.ObjectId, ref: 'Exam', required: true },
  title: { type: String, required: true, trim: true },
  duration: { type: Number, required: true, min: 1 },
  totalMarks: { type: Number, required: true, min: 0 },
  negativeMarking: { type: Number, default: 0, min: 0 },
  sections: [{
    name: { type: String, required: true, trim: true },
    totalQuestions: { type: Number, required: true, min: 1 },
    marksPerQuestion: { type: Number, required: true, min: 0 },
    negativePerQuestion: { type: Number, default: 0, min: 0 },
    sectionDuration: { type: Number, min: 0 }
  }]
}, { timestamps: true });

const practiceTestSchema = new mongoose.Schema({
  examPattern: { type: mongoose.Schema.Types.ObjectId, ref: 'ExamPattern', required: true },
  title: { type: String, required: true, trim: true },
  slug: { type: String, lowercase: true, trim: true },
  totalMarks: { type: Number, required: true, min: 0 },
  duration: { type: Number, required: true, min: 1 },
  accessLevel: { type: String, enum: ['FREE', 'PRO'], default: 'FREE' },
  isPYQ: { type: Boolean, default: false },
  pyqYear: { type: Number, default: null },
  pyqShift: { type: String, default: null, trim: true },
  pyqExamName: { type: String, default: null, trim: true },
  publishedAt: { type: Date, default: Date.now },
  questions: [{
    questionText: { type: String, required: true },
    questionImage: { type: String, default: '' },
    options: [{ type: String, required: true }],
    optionImages: [{ type: String, default: '' }],
    correctAnswerIndex: { type: Number, required: true, min: 0 },
    explanation: { type: String, trim: true },
    section: { type: String, required: true, trim: true },
    tags: [{ type: String, trim: true }],
    difficulty: { type: String, enum: ['easy', 'medium', 'hard', 'mixed'], default: 'medium' }
  }]
}, { timestamps: true });

const ExamCategory = mongoose.models.ExamCategory || mongoose.model('ExamCategory', examCategorySchema);
const Exam = mongoose.models.Exam || mongoose.model('Exam', examSchema);
const ExamPattern = mongoose.models.ExamPattern || mongoose.model('ExamPattern', examPatternSchema);
const PracticeTest = mongoose.models.PracticeTest || mongoose.model('PracticeTest', practiceTestSchema);

const REA = 'General Intelligence';
const ENG = 'English Language';
const QA  = 'Quantitative Aptitude';
const GA  = 'General Awareness';

const KEY = [1, 3, 1, 2, 1, 2, 2, 3, 2, 4, 1, 2, 1, 1, 2, 2, 4, 4, 4, 4, 2, 4, 1, 3, 1, 3, 2, 3, 3, 2, 3, 3, 4, 4, 2, 2, 3, 4, 2, 3, 2, 2, 2, 1, 3, 1, 2, 2, 1, 3, 3, 2, 3, 2, 1, 2, 1, 1, 2, 2, 2, 3, 2, 3, 2, 3, 4, 3, 2, 2, 3, 4, 1, 1, 1, 1, 1, 2, 3, 1, 2, 3, 3, 4, 2, 1, 4, 3, 2, 1, 1, 1, 2, 1, 3, 3, 4, 1, 2, 2];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `What comes next in the series 7 : 336 :: 11 : ?`, o: [`1320`, `1210`, `1440`, `1331`], e: `7 : 336 :: 11 : ? Created FromLDoagteic: Created To Date Number (Number)³ - Number mm / dd / yyyEyxp--la: -n-at-i-on: mm/dd/yyyy --:-- -- Search Clear 7³ - 7 = 343 - 7 = 336 11³ - 11 = 1331 - 11 = 1320 Thus, correct option is (A). CATEGORY (MINS) AT AT PATH` },
  { s: `General Intelligence`, q: `What comes nextSienletchteiosneries 4 : 17 :: 10 : ? 19, 2026, 28, 2026, LENGTH 18:28:16 14:23:51`, o: [`99`, `100`, `101`, `102`], e: `25 Jul 2025 S2) Sol: Given: Logic: Selection Selection 19, 2026, 28, 2026, Number (NumbePr)o²s+t 1 Post 18:28:17 14:15:57 Explanation: (Higher (4)² + 1 = 16 + 1Se=co1n7dary) 10² + 1 = 100 + 1 S=im10ila1r Thus, correct optioPnaipse(Cr ). (Held on 25 Jul 2025 S2)` },
  { s: `General Intelligence`, q: `Instruction: Apply consistent positional logic to decode the second pair. JKL : MNO :: PQR : ?`, o: [`STU`, `RST`, `TUV`, `QRS`], e: `Given: JKL : MNO :: PQR : ? Logic: Each letter in the first group is shifted forward by 3 positions to form the second group. JKL MNO J +3 M, K +3 N, L +3 O PQR ? P +3 S, Q +3 T, R +3 U Thus, correct option is (A).` },
  { s: `General Intelligence`, q: `If "GOLD" is coded as "HOME", then "SONG" will be coded as:`, o: [`TONG`, `TOOH`, `TPOH`, `SOHH`], e: `Information Given: GOLD HOME Logic: consonants +1, vowels same. Explanation Logic: Verify pattern on GOLD. Step-by-step: G (consonant) H (+1) O (vowel) O (same) L (consonant) M (+1) D (consonant) E (+1) Rule fits perfectly. Apply to SONG: S T (+1) O O (same) N O (+1) G H (+1) Final Answer: TOOH Final Correct Option: B` },
  { s: `General Intelligence`, q: `If 12 / 3 = 5, 15 / 5 = 4, then 18 / 2 = ?`, o: [`10`, `9`, `8`, `11`], e: `Given: 12 / 3 = 5, 15 / 5 = 4, 18 / 2 = ? Logic: Result = (First number ÷ Second number) + 1 12 ÷ 3 = 4, 4 + 1 = 5 15 ÷ 5 = 3, 3 + 1 = 4 18 ÷ 2 = 9, 9 + 1 = 10 Thus, correct option is (A).` },
  { s: `General Intelligence`, q: `Which letter will come next in the series? Z, X, V, T, ?`, o: [`S`, `R`, `Q`, `U`], e: `Given: Z, X, V, T, ? Logic: Each letter is moving backward by 2 positions in the English alphabet. Z -2 X X -2 V V -2 T T -2 R Thus, correct option is (B).` },
  { s: `General Intelligence`, q: `Fill in the next missing number: 5, 10, 20, 40, ?`, o: [`60`, `80`, `50`, `100`], e: `Given: 5, 10, 20, 40, ? Logic: Each number is multiplied by 2. 5 × 2 = 10 10 × 2 = 20 20 × 2 = 40 40 × 2 = 80 Thus, correct option is (B).` },
  { s: `General Intelligence`, q: `Choose the odd one out: 5, 10, 15, 20, 26, 30`, o: [`15`, `20`, `26`, `30`], e: `Given: 5, 10, 15, 20, 26, 30 Logic: All numbers except one are multiples of 5. 5=5×1 10 = 5 × 2 15 = 5 × 3 20 = 5 × 4 26 is not a multiple of 5 30 = 5 × 6 Thus, correct option is (C).` },
  { s: `General Intelligence`, q: `Find the missing letter in the series: A, D, G, J, ?`, o: [`L`, `M`, `N`, `K`], e: `Given: A, D, G, J, ? Logic: Each letter is moved forward by 3 positions in the English alphabet. A +3 D D +3 G G +3 J J +3 M Thus, correct option is (B).` },
  { s: `General Intelligence`, q: `Which of the following numbers is different from the rest?`, o: [`49`, `121`, `144`, `150`], e: `Logic: All except one are perfect squares. Explanation: Option A: 49 = 7² (perfect square) Option B: 121 = 11² (perfect square) Option C: 144 = 12² (perfect square) Option D: 150 is not a perfect square T hus, correct option is (D).` },
  { s: `General Intelligence`, q: `"Battery : Torch" is related to "Fuel : ?"`, o: [`Engine`, `Gas`, `Smoke`, `Heat`], e: `Given: Battery : Torch :: Fuel : ? Logic: The first item is a source of energy used to operate the second item. A battery provides energy to run a torch. Similarly, fuel provides energy to run an engine. Thus, correct option is (A).` },
  { s: `General Intelligence`, q: `Find the alternative that will replace the question mark. Architect : Building :: Sculptor : ?`, o: [`Museum`, `Statue`, `Chisel`, `Stone`], e: `Given: Architect : Building :: Sculptor : ? Logic: A person is related to what they create. An architect designs a building. A sculptor creates a statue. Thus, correct option is (B).` },
  { s: `General Intelligence`, q: `What should come at the place of question mark? BDF : HJL :: NPR : ?`, o: [`TVX`, `UWY`, `TUV`, `VXZ`], e: `Given: BDF : HJL :: NPR : ? Logic: Each letter in the first group is shifted forward by 6 positions to form the second group. BDF HJL B +6 H, D +6 J, F +6 L NPR ? N +6 T, P +6 V, R +6 X So, the missing group is TVX. Thus, correct option is (A).` },
  { s: `General Intelligence`, q: `Identify the pattern and choose the correct option: If 5 @ 3 = 16, 8 & 2 = 60, then 10 @ 4 = ?`, o: [`84`, `100`, `96`, `116`], e: `Given: 5 @ 3 = 16, 8 & 2 = 60, 10 @ 4 = ? Logic: A @ B = A² - B² 5 @ 3 = 5² - 3² = 25 - 9 = 16 10 @ 4 = 10² - 4² = 100 - 16 = 84 Thus, correct option is (A).` },
  { s: `General Intelligence`, q: `If 4 + 2 = 20, 6 + 3 = 45, then 7 + 5 = ?`, o: [`70`, `74`, `84`, `90`], e: `Given: 4 + 2 = 20, 6 + 3 = 45, 7 + 5 = ? Logic: Result = (First number)² + (Second number)² 4² + 2² = 16 + 4 = 20 6² + 3² = 36 + 9 = 45 Similarly, 7² + 5² = 49 + 25 = 74 Thus, correct option is (B).` },
  { s: `General Intelligence`, q: `If A * B means A is multiplied by B and the result is halved, find 6 * 4:`, o: [`24`, `12`, `10`, `6`], e: `Given: A * B means A is multiplied by B and the result is halved. Logic: A * B = (A × B) ÷ 2 Explanation: 6 * 4 = (6 × 4) ÷ 2 = 24 ÷ 2 = 12 Thus, correct option is (B).` },
  { s: `General Intelligence`, q: `Direction: Four words have been given, out of which three are alike and the fourth one is different. Choose the odd one out.`, o: [`Physics`, `Botany`, `Zoology`, `History`], e: `Given: Physics, Botany, Zoology, History Logic: Three subjects are branches of science, while one is not. Explanation: Physics is a branch of science. Botany is a branch of science. Zoology is a branch of science. History is not a branch of science. Thus, correct option is (D).` },
  { s: `General Intelligence`, q: `Which item does NOT fit the group?`, o: [`Hammer`, `Screwdriver`, `Pliers`, `Nail`], e: `Logic: Three are tools; one is not. Explanation: Option A: Hammer tool Option B: Screwdriver tool Option C: Pliers tool Option D: Nail not a tool (fastener) Thus, correct option is (D).` },
  { s: `General Intelligence`, q: `Which of the following words CANNOT be formed using the letters of the word "EDUCATION"?`, o: [`NOTE`, `DEAN`, `CAUTION`, `DUCKS`], e: `Given: Word: EDUCATION Logic: Check whether all letters of each option are present in the given word. Explanation: NOTE N, O, T, E (all present) DEAN D, E, A, N (all present) CAUTION C, A, U, T, I, O, N (all present) DUCKS D, U present but C, K, S are not all available (K and S are missing) Thus, correct option is (D).` },
  { s: `General Intelligence`, q: `Which of the following words CANNOT be formed using the word "DISTRIBUTION" without repeating letters?`, o: [`TRUST`, `BIRD`, `DUST`, `KITE`], e: `Given: Word: DISTRIBUTION Logic: Check whether all letters of each option are present in the given word without repeating letters. Explanation: Option A: TRUST T, R, U, S, T (all letters present; T appears twice and is available) Option B: BIRD B, I, R, D (all letters present) Option C: DUST D, U, S, T (all letters present) Option D: KITE K, I, T, E (K and E are not present) Thus, correct option is (D).` },
  { s: `General Intelligence`, q: `From the letters of the word "PRODUCT", how many distinct 4-letter words can be formed if the word must start and end with a vowel?`, o: [`120`, `40`, `60`, `0`], e: `Given: Word: PRODUCT (all letters distinct) Vowels: O, U Condition: 4-letter word must start and end with a vowel, no repetition Concept Used: Permutation without repetition Start and end positions: O__U U__O Formula Used: P n r = n! (n - r)! Solution: There are 2 vowels O and U. They must occupy the first and last positions without repetition. Remaining letters are 5 consonants: P, R, D, C, T. Fill the middle two positions using these consonants: Number of ways = 5 × 4 = 20 Total number of words = 2 × 20 = 40` },
  { s: `General Intelligence`, q: `Read the statement carefully and identify the conclusion that follows. Statement: All good athletes eat healthily. John eats healthily.`, o: [`John is a good athlete`, `John is not a good athlete`, `John might be a good athlete`, `Data is insufficient`], e: `Given: Statement: All good athletes eat healthily. John eats healthily. Logic: If all good athletes eat healthily, it does not mean that everyone who eats healthily is a good athlete. Eating healthily is a common condition, not a sufficient condition. John eats healthily, but there is no information stating that only good athletes eat healthily. So, John may or may not be a good athlete. Thus, correct option is (C).` },
  { s: `General Intelligence`, q: `Instruction: Follow the exact letter shifts. WARM : XBSN :: COLD : ?`, o: [`DPME`, `DOME`, `DQNF`, `EPME`], e: `Given: WARM : XBSN :: COLD : ? Logic: Each letter is shifted one position forward in the English alphabet. Explanation: W +1 X, A +1 B, R +1 S, M +1 N Applying the same logic: C +1 D, O +1 P, L +1 M, D +1 E So, COLD DPME Thus, correct option is (A).` },
  { s: `General Intelligence`, q: `M is 7 m South of L. N is 10 m West of M. O is 7 m South of N. In which direction is O from L?`, o: [`East`, `North - East`, `South - West`, `North - West`], e: `Given: M is 7m South of L. N is 10 m West of M. O is 7 m South of N. O is in the South - West to L.` },
  { s: `General Intelligence`, q: `Point Y is 12 m North of Point X. Point Z is 12 m East of Point Y. Point W is 12 m South of Point Z. How far is W from X?`, o: [`12`, `24`, `0`, `6`], e: `Given: Point Y is 12 m North of Point X. Point Z is 12 m East of Point Y. Point W is 12 m South of Point Z. W is 12 m far from X.` },
  { s: `General Awareness`, q: `How many members can be nominated by the President of India to the Rajya Sabha?`, o: [`8`, `10`, `12`, `14`], e: `The correct answer is (C) 12 Explanation: · Under Article 80 of the Constitution, the Council of States (Rajya Sabha) is composed of not more than 250 members, of whom 12 are nominated by the President of India. · These members are persons having special knowledge or practical experience in fields such as Literature, Science, Art, and Social Service. Information Booster: · The Rajya Sabha is a permanent body and is not subject to dissolution. · One-third of its members retire every second year. Additional Knowledge: · 14 (Option D): Previously, the President could nominate 2 members from the Anglo-Indian community to the Lok Sabha (total 12+2=14), but this was abolished by the 104th Constitutional Amendment Act, 2019.` },
  { s: `General Awareness`, q: `What is the primary function of mitochondria in a cell?`, o: [`Protein synthesis`, `Energy production`, `Cell division`, `Storage of genetic material`], e: `The correct answer is (B) Energy production Explanation: · Mitochondria are known as the 'Powerhouse of the Cell' because they generate most of the cell's supply of adenosine triphosphate (ATP). · ATP is used as a source of chemical energy for various cellular processes. Information Booster: · Mitochondria have their own DNA and ribosomes, allowing them to produce some of their own proteins. Additional Knowledge: · Protein synthesis (Option A): Primary function of Ribosomes. · Storage of genetic material (Option D): Primary function of the Nucleus.` },
  { s: `General Awareness`, q: `Which is the largest freshwater lake in India by surface area?`, o: [`Dal Lake`, `Chilika Lake`, `Wular Lake`, `Vembanad Lake`], e: `The correct answer is (C) Wular Lake Explanation: · Wular Lake, located in the Bandipora district of Jammu and Kashmir, is one of the largest freshwater lakes in Asia. · It was formed as a result of tectonic activity and is fed by the Jhelum River. Information Booster: · Wular Lake is a designated Ramsar site, highlighting its international ecological importance. Additional Knowledge: · Chilika Lake (Option B): The largest brackish water lagoon in India. · Vembanad Lake (Option D): The longest lake in India, located in Kerala.` },
  { s: `General Awareness`, q: `Which of the following actions can lead to the impeachment of the President of India?`, o: [`Dissolving the Lok Sabha`, `Addressing Parliament`, `Violating the Constitution`, `Appointing Governors`], e: `The correct answer is (C) Violating the Constitution Explanation: · Article 61 of the Indian Constitution provides the procedure for the impeachment of the President. · The only ground for impeachment mentioned in the Constitution is 'Violation of the Constitution'. Information Booster: · Impeachment charges can be initiated by either House of Parliament. · No President has been impeached in India so far. Additional Knowledge: · Dissolving the Lok Sabha (Option A): Done by the President on the advice of the Council of Ministers; it is a constitutional power, not a violation.` },
  { s: `General Awareness`, q: `What was a major cause behind the \`Deccan Riots' of 1875?`, o: [`Decline in textile exports`, `Heavy taxation and exploitation by moneylenders`, `Introduction of railways`, `Partition of Bengal`], e: `The correct answer is (B) Heavy taxation and exploitation by moneylenders Explanation: · The riots began in Supa village (Pune) and spread across the Deccan region. · Farmers were burdened by high land revenue under the Ryotwari system and trapped in debt cycles by moneylenders (Sahukars). Information Booster: · Following the riots, the British government passed the Deccan Agriculturists' Relief Act of 1879 to protect farmers from moneylenders. Additional Knowledge: · Partition of Bengal (Option D): Occurred in 1905, much later than the Deccan Riots.` },
  { s: `General Awareness`, q: `Which statement best describes Stage IV of demographic transition?`, o: [`High birth and death rates`, `Declining death rate and high birth rate`, `Low birth and death rates`, `Rapid population growth`], e: `The correct answer is (C) Low birth and death rates Explanation: · Stage IV represents a developed society where both birth rates and death rates are low. · The population becomes stable or grows very slowly. Information Booster: · Stage I: High Birth and Death rates (Pre-industrial). · Stage II: High Birth rate and declining Death rate (Population Explosion). · Stage III: Declining Birth rate and low Death rate. Additional Knowledge: · Some theories include a Stage V where the birth rate falls below the death rate, leading to population decline.` },
  { s: `General Awareness`, q: `Which of the following is a major objective of progressive taxation?`, o: [`To increase income inequality`, `To reduce government expenditure`, `To redistribute income and reduce inequality`, `To eliminate indirect taxes`], e: `The correct answer is (C) To redistribute income and reduce inequality Explanation: · In a progressive tax system, the tax rate increases as the taxable amount increases. · This ensures that those with a higher ability to pay contribute more, which the government then uses for social welfare, thereby reducing the gap between the rich and the poor. Information Booster: · Income Tax in India is a classic example of progressive taxation. Additional Knowledge: · Regressive Tax: A tax where the rate decreases as the income increases (often indirect taxes are considered regressive in effect).` },
  { s: `General Awareness`, q: `Which of the following is NOT a component of the revenue deficit?`, o: [`Revenue expenditure`, `Revenue receipts`, `Interest payments`, `Capital expenditure`], e: `The correct answer is (D) Capital expenditure Explanation: · Revenue Deficit occurs when the government's total reveCnoupeyreixgphetn©di2tu0r2e6eAxcdedead2s47its total revenue receipts. · Capital expenditure relates to the creation of assets or reduction of liabilities and is part of the Capital Budget, not the Revenue Budget. Information Booster: · Revenue Expenditure includes salaries, pensions, and interest payments. · Revenue Receipts include tax revenue and non-tax revenue (like dividends and interest). Additional Knowledge: · Fiscal Deficit: The difference between total expenditure and total receipts (excluding borrowings).` },
  { s: `General Awareness`, q: `Which of the following schemes provides direct income support to farmers?`, o: [`Pradhan Mantri Fasal Bima Yojana`, `Soil Health Card Scheme`, `Paramparagat Krishi Vikas Yojana`, `Pradhan Mantri Kisan Samman Nidhi (PM-KISAN)`], e: `The correct answer is (D) Pradhan Mantri Kisan Samman Nidhi (PM-KISAN) Explanation: · PM-KISAN is a Central Sector scheme that provides an income support of 6,000 per year in three equal installments to all landholding farmer families. · It was launched to supplement the financial needs of farmers in procuring inputs and ensuring crop health. Information Booster: · The scheme was launched in February 2019 (effective from Dec 2018). Additional Knowledge: · Pradhan Mantri Fasal Bima Yojana (Option A): An insurance-based scheme for crop failure. · Soil Health Card (Option B): Provides information to farmers on nutrient status of their soil.` },
  { s: `General Awareness`, q: `Which pollutants are primarily monitored under the National Air Quality Index (AQI) in India?`, o: [`CO and methane`, `PM2.5 and PM10`, `Nitrogen and hydrogen`, `Helium and ozone`], e: `The correct answer is (B) PM2.5 and PM10 Explanation: · The AQI in India monitors 8 major pollutants: PM10, PM2.5, NO, SO, CO, O (Ozone), NH (Ammonia), and Pb (Lead). · PM2.5 and PM10 are particulate matters that have significant health impacts due to their ability to penetrate deep into the respiratory system. Information Booster: · AQI has six categories: Good, Satisfactory, Moderately polluted, Poor, Very Poor, and Severe. Additional Knowledge: · CO (Option A): While it is a greenhouse gas, it is not usually a 'pollutant' monitored under standard AQI levels because it doesn't have immediate local toxicity compared to CO.` },
  { s: `General Awareness`, q: `Who is set to become the first Indian woman to command the International Space Station (ISS)?`, o: [`Kalpana Chawla`, `Sunita Williams`, `Tessy Thomas`, `Ritu Karidhal`], e: `The correct answer is (B) Sunita Williams Explanation: · Sunita Williams, an Indian-origin NASA astronaut, has been selected to command the ISS during Expedition 71. · She holds several records for spaceflights and spacewalks by a woman. Information Booster: · The International Space Station (ISS) is a modular space station in low Earth orbit, a collaborative project between NASA, Roscosmos, JAXA, ESA, and CSA. Additional Knowledge: · Kalpana Chawla (Option A): The first woman of Indian origin to go to space. · Tessy Thomas (Option C): Known as the 'Missile Woman of India'.` },
  { s: `General Awareness`, q: `A car is moving in a circular track with uniform speed. Which of the following statements is correct?`, o: [`The car has zero acceleration because its speed is constant.`, `The direction of the car's velocity does not change.`, `The car experiences centripetal acceleration towards the centre.`, `The motion is non-uniform because the speed changes.`], e: `The correct answer is (C) The car experiences centripetal acceleration towards the centre. Explanation: · Even if the speed is uniform, the direction of velocity changes at every point in circular motion. · A change in velocity (direction) means the object is accelerating. This acceleration is directed towards the center of the circle and is called centripetal acceleration. Information Booster: · The magnitude of centripetal acceleration is given by a = v²/r. Additional Knowledge: · Option A is wrong because speed is a scalar, but velocity is a vector; change in direction means acceleration is not zero.` },
  { s: `General Awareness`, q: `Which Mandal of the Rigveda is primarily devoted to hymns dedicated to Indra?`, o: [`First`, `Second`, `Third`, `Eighth`], e: `The correct answer is (D) Eighth Explanation: · While Indra is the most celebrated deity in the Rigveda with about 250 hymns across various Mandals, the Eighth Mandal contains a very high concentration of hymns specifically for him. · Indra is regarded as the god of rain and thunder (Purandara - breaker of forts). Information Booster: · The Rigveda consists of 10 Mandals (books) and 1028 hymns (Suktas). Additional Knowledge: · Third Mandal (Option C): Contains the Gayatri Mantra, dedicated to the solar deity Savitr.` },
  { s: `General Awareness`, q: `The Indo-Islamic architecture is best known for which of the following features?`, o: [`Sloping wooden roofs`, `Large domes and pointed arches`, `Thatched structures`, `Mud-brick walls`], e: `The correct answer is (B) Large domes and pointed arches Explanation: · Indo-Islamic architecture introduced the 'Arcuate' style (arches and domes) to India, replacing the 'Trabeate' style (beams and lintels). · Key features include minarets, calligraphy, and floral patterns instead of human figures. Information Booster: · Examples include the Taj Mahal, Qutub Minar, and Gol Gumbaz. Additional Knowledge: · Sloping wooden roofs (Option A): Characteristics of Himalayan or Kerala temple architecture.` },
  { s: `General Awareness`, q: `Which two countries are central partners in the India-Middle East-Europe Economic Corridor (IMEC)?`, o: [`Egypt and Turkey`, `Oman and Kuwait`, `Saudi Arabia and UAE`, `Lebanon and Syria`], e: `The correct answer is (C) Saudi Arabia and UAE Explanation: · IMEC was announced at the 2023 G20 Summit in New Delhi. · It consists of two corridors: the East Corridor connecting India to the Arabian Gulf and the Northern Corridor connecting the Arabian Gulf to Europe via Saudi Arabia and the UAE. Information Booster: · IMEC is seen as a counter to China's Belt and Road Initiative (BRI). Additional Knowledge: · The project involves rail, ship-to-rail transit networks, and data/energy cables.` },
  { s: `General Awareness`, q: `What type of services does AIIMS primarily provide?`, o: [`Agricultural research`, `Advanced medical treatment, education, and research`, `Industrial consultancy`, `Financial investment services`], e: `The correct answer is (B) Advanced medical treatment, education, and research Explanation: · AIIMS (All India Institute of Medical Sciences) is a group of autonomous public medical universities of higher education. · They serve as institutions of national importance, providing tertiary-level healthcare and conducting medical research. Information Booster: · The first AIIMS was established in New Delhi in 1956. Additional Knowledge: · Agricultural research (Option A): Primarily handled by ICAR (Indian Council of Agricultural Research).` },
  { s: `General Awareness`, q: `Which book by Ramachandra Guha explores the history of independent India?`, o: [`The Discovery of India`, `India After Gandhi`, `The Anarchy`, `The Idea of India`], e: `The correct answer is (B) India After Gandhi Explanation: · 'India After Gandhi: The History of the World's Largest Democracy' is a seminal work by Ramachandra Guha that covers India's history from 1947 onwards. · It details the challenges of nation-building, wars, and political evolution. Information Booster: · Ramachandra Guha is a renowned Indian historian and biographer of Mahatma Gandhi. Additional Knowledge: · The Discovery of India (Option A): Written by Jawaharlal Nehru. · The Anarchy (Option C): Written by William Dalrymple.` },
  { s: `General Awareness`, q: `What is the primary objective of the National Anti-Doping Agency (NADA)?`, o: [`Promote sports tourism`, `Enforce anti-doping rules in sports`, `Organize Olympic events`, `Provide scholarships to athletes`], e: `The correct answer is (B) Enforce anti-doping rules in sports Explanation: · NADA is the national organization responsible for promoting, coordinating, and monitoring the doping control program in all forms of sports in India. · It works in accordance with the World Anti-Doping Agency (WADA) code. Information Booster: · NADA's primary motto is 'Play Fair'. Additional Knowledge: · Doping refers to the use of banned performance-enhancing substances by athletes.` },
  { s: `General Awareness`, q: `Given below are Column A (Organizations) and Column B (Headquarters). Choose the correct option by matching them. Column A ­ OrganizationColumn B ­ Headquarters`, o: [`A-ii, B-iv, C-iii, D-i`, `A-i, B-ii, C-iv, D-iii`, `A-iii, B-i, C-ii, D-iv`, `A-iv, B-iii, C-i, D-ii`], e: `The correct answer is (A) A-ii, B-iv, C-iii, D-i Explanation: · ASEAN (Association of Southeast Asian Nations) is headquartered in Jakarta, Indonesia. · SAARC (South Asian Association for Regional Cooperation) is headquartered in Kathmandu, Nepal. · African Union (AU) is headquartered in Addis Ababa, Ethiopia. · European Union (EU) is headquartered in Brussels, Belgium. Information Booster: · SAARC was established in 1985 in Dhaka. · ASEAN was established in 1967 with the Bangkok Declaration. Additional Knowledge: · Brussels (Option D-i) also serves as the headquarters for NATO.` },
  { s: `General Awareness`, q: `Which of the following countries is NOT a member of BRICS?`, o: [`India`, `Brazil`, `Germany`, `South Africa`], e: `The correct answer is (C) Germany Explanation: · BRICS is an acronym for Brazil, Russia, India, China, and South Africa. · Germany is a member of the G7 and the EU but not BRICS. Information Booster: · From January 1, 2024, BRICS expanded to include new members like Egypt, Ethiopia, Iran, and the UAE. Additional Knowledge: · The term 'BRIC' was coined by Jim O'Neill in 2001; South Africa joined in 2010.` },
  { s: `General Awareness`, q: `Which of the following statements are correct regarding the Digital Personal Data Protection Act, 2023? 1. It regulates the processing of digital personal data. 2. It applies to data processed within India and outside India if offering goods or services in India. 3. It completely bans cross-border data transfer. 4. It provides rights to individuals regarding their personal data.`, o: [`1, 2, and 4 only`, `1 and 3 only`, `2, 3, and 4 only`, `1, 2, 3, and 4`], e: `The correct answer is (A) 1, 2, and 4 only Explanation: · Statement 1 is correct: The Act provides for the processing of digital personal data in a manner that recognizes both the right of individuals to protect their personal data and the need to process such personal data for lawful purposes. · Statement 2 is correct: It has extra-territorial jurisdiction if data is processed outside India in connection with any activity related to offering goods or services to Data Principals within India. · Statement 4 is correct: It grants individuals (Data Principals) rights such as the right to access, correction, and erasure. Information Booster: · Statement 3 is incorrect because the Act allows cross-border data transfer to certain countries/territories unless specifically restricted by the Centra` },
  { s: `General Awareness`, q: `One of the key objectives of ISRO's Aditya-L1 Mission is to study the ______ of the Sun.`, o: [`Ocean currents`, `Corona and solar wind`, `Asteroid belt`, `Lunar surface`], e: `The correct answer is (B) Corona and solar wind Explanation: · Aditya-L1 is India's first solar mission, designed to studyCthoepySruignh'st a©tm2o0s2p6hAedred,as2p4e7cifically the chromosphere and the outermost layer called the Corona. · It aims to understand Coronal Mass Ejections (CMEs), solar flares, and solar wind properties. Information Booster: · The spacecraft is placed in a halo orbit around the Lagrange point 1 (L1) of the Sun-Earth system, about 1.5 million km from Earth. Additional Knowledge: · Lunar surface (Option D): This was the primary objective of the Chandrayaan missions.` },
  { s: `General Awareness`, q: `When was the Shanghai Cooperation Organisation (SCO) established?`, o: [`1995`, `2001`, `2005`, `2010`], e: `The correct answer is (B) 2001 Explanation: · The SCO was announced on June 15, 2001, in Shanghai by the leaders of China, Russia, Kazakhstan, Kyrgyzstan, Tajikistan, and Uzbekistan. · It evolved from the 'Shanghai Five' mechanism founded in 1996. Information Booster: · India and Pakistan became full members of the SCO in 2017 during the Astana Summit. · Iran became a full member in 2023. Additional Knowledge: · The SCO's Regional Anti-Terrorist Structure (RATS) is based in Tashkent.` },
  { s: `General Awareness`, q: `"Laylat al-Qadr" is referred to as the "Night of":`, o: [`Power`, `Forgiveness`, `Resurrection`, `Revelation`], e: `The correct answer is (A) Power Explanation: · Laylat al-Qadr, also known as the Night of Power or Decree, is considered the holiest night in Islam. · It is believed to be the night when the first verses of the Quran were revealed to Prophet Muhammad. Information Booster: · It occurs during one of the odd-numbered nights of the last ten days of Ramadan. Additional Knowledge: · The Quran states that worship on this single night is better than worship for a thousand months.` },
  { s: `General Awareness`, q: `The term "Vis" in the Rig Vedic period primarily referred to:`, o: [`A king`, `A priestly class`, `A clan or a group of families`, `A village assembly`], e: `The correct answer is (C) A clan or a group of families Explanation: · In Early Vedic society, 'Vis' was a subdivision of the tribe (Jana). · The common people were often called 'Vis'. Information Booster: · The king was often called 'Vispati' or 'Gopa'. Additional Knowledge: · A priestly class (Option B): Known as Brahmins. · A village assembly (Option D): Known as the Grama or Sabha/Samiti.` },
  { s: `Quantitative Aptitude`, q: `A large solid metallic sphere of radius 10 cm is melted to form small spheres of radius 2 cm. How many such small spheres can be formed?`, o: [`64`, `100`, `125`, `250`], e: `Given: R = 10 cm, r = 2 cm. Formula Used: Number = Volume of Big Sphere = R3 r 3 Volume of Small Sphere Solution: N = ( 10 3 = 53 = 125. 2 ) Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Consider the following statements. Assertion (A): 1 is a prime number. Reason (R): A prime number has exactly two factors, 1 and itself.`, o: [`Both A and R are true`, `A is false, but R is true`, `A is true, but R is false`, `Both A and R are false`], e: `Given: Assertion (A): 1 is a prime number. Reason (R): Prime number definition (exactly two factors). Solution: Check A: 1 is NOT a prime number. It has only one factor (1). So A is false. Check R: The definition of a prime number is indeed that it has exactly two distinct factors: 1 and the number itself. So R is true. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A shopkeeper allows a discount of 10% on the marked price and gains 20%. If the cost price is 900, find the marked price.`, o: [`1100`, `1150`, `1200`, `1080`], e: `Given: Discount = 10%. Gain = 20%. CP = 900. Formula Used: MP 100 + P % = CP 100 - D% Solution: MP 120 = 900 90 120 MP = 900 × = 10 × 120 = 1200. 90 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `From the top of a 50m high tower, the angle of depression of a car on the ground is 30. What is the distance of the car from the base of the tower?`, o: [`50 m`, `50`, `25`, `100m`], e: `Given: Height h = 50 m. Angle = 30 Formula Used: Distance = h cot Solution: D istance = 50 × cot 30 c ot 30 = 3 Distance = 50 3 m Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `What is the smallest positive integer by which 72 must be multiplied to make it a perfect square?`, o: [`2`, `3`, `4`, `6`], e: `Given: Number 72. Solution: Prime factorization of 72 =36 × 2 = 62 × 2 = 23 × 32. To make the power of 2 even, we need to multiply by 2. 7 2 × 2 = 144 = 122. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `In PQR, Q = 90. S is the midpoint of PQ, and ST is drawn perpendicular to PR. If PQ = 6 cm and QR = 8cm, find the length of PR.`, o: [`12 cm`, `10 cm`, `14 cm`, `9 cm`], e: `Given: Right PQR (at Q). PQ = 6, QR = 8. Formula Used: Pythagoras Theorem: P R2 = P Q2 + QR2 Solution: PR = 62 + 82 = 36 + 64 = 100 = 10 cm. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A warehouse has a floor in the shape of a rectangle 20 m \\times 15 m, with a triangular extension on one end. The triangle has a base of 15 m and a height of 8 m. What is the total area of the floor?`, o: [`360 m2`, `350 m2`, `340 m2`, `380 m2`], e: `Given: Rectangle: 20m × 15m. Triangle: Base = 15 m, Height = 8 m. Formula Used: Area = Area of Rectangle + Area of Triangle 1 Area = (l × b) + ( × base × height) 2 Solution: Area of Rectangle = 20 × 15 = 300 m2 Area of Triangle = 1 × 15 × 8 = 15 × 4 = 60 m2 2 Total Area = 300 + 60 = 360 m2 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Pipe A can fill a tank in 10 hours, and Pipe B can fill it in 15 hours. Pipe C can empty the tank in 12 hours. If all three are opened together, how long will it take to fill the tank?`, o: [`12 hours`, `15 hours`, `20 hours`, `10 hours`], e: `Given: Rates: A = +1/10, B = +1/15, C = -1/12. Solution: 111 Net Rate = + - 610+ 4 -155 125 1 Net Rate = == 60 60 12 Time = 12 hours. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A man invests 10,000 at 10% compound interest per annum. After 1 year, he adds 5,000 more. What will be the total amount at the end of 2 years from the start?`, o: [`17,500`, `17,600`, `18,150`, `16,500`], e: `Given: Initial P = 10,000. Rate = 10%. After 1 year, adds 5,000. Solution: Amount after 1 year = 10,000 × 1.10 = 11,000. New Principal for 2nd year = 11,000 + 5,000 = 16,000. Interest for 2nd year = 16,000 × 10% = 1,600. Total Amount at end of year 2 = 16,000 + 1,600 = 17,600. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A retailer lists a shirt for 3000. He offers a discount of 20% on the list price. What additional discount must he offer to bring the final price down to 2160?`, o: [`8%`, `10%`, `12%`, `15%`], e: `Given: List Price (LP) = 3000. First Discount (D1) = 20%. Final Price (SP) = 2160. Formula Used: SP = LP(1 - D1/100)(1 - D2/100) Solution: Price after first discount = 3000 × 0.80 = 2400. Required reduction = 2400 - 2160 = 240. Additional Discount % = 240 × 100 = 10%. 2400 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A quadrilateral PQRS is cyclic. If P = 85and R = 95, what is the value of Q + S?`, o: [`160`, `180`, `190`, `200`], e: `Given: Cyclic Quadrilateral PQRS. P = 85, R = 95. Formula Used: Sum of opposite angles in a cyclic quadrilateral is 180 Sum of all internal angles is 360 Solution: Check given angles: P + R = 85 + 95 = 180 (This confirms it's cyclic). We need Q + S. Since Q and S are also opposite angles, their sum must be 180. Q + S = 180. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Which of the following is a correct property regarding circles?`, o: [`The angle subtended by an arc at the centre is half the angle subtended by it at any point on the remaining part of the circle.`, `Angles in the same segment of a circle are unequal.`, `The angle subtended by an arc at the centre is double the angle subtended by it at any point on the remaining part of the circle.`, `A cyclic parallelogram is a rhombus.`], e: `Given: Statements about circle properties. Formula Used: Standard Circle Theorems. Solution: A: False. Angle at center is double, not half. B: False. Angles in the same segment are equal. C: True. This is a fundamental theorem (Angle at Center Theorem). D: False. A cyclic parallelogram is a rectangle. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A person completes 3/5 of a task on Day 1. On Day 2, he completes 1/4 of the remaining work. What fraction of the total work is left?`, o: [`1/10`, `3/10`, `3/20`, `1/5`], e: `Given: Day 1 work = 3/5. Remaining = 2/5. Day 2 work = 1/4 of Remaining = 1/4 \\times 2/5 = 1/10. Solution: Total work done = 3/5 + 1/10 = 6/10 + 1/10 = 7/10. Work Left = 1 - 7/10 = 3/10. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `If the cost price of 20 articles is equal to the selling price of 15 articles, what is the profit percentage?`, o: [`25%`, `30%`, `33.33%`, `40%`], e: `Given: CP of 20 = SP of 15 Formula Used: Profit % = Goods Left × 100 Goods Sold Solution: Let CP of 1 article = 1. CP of 15 = 15. SP of 15 = CP of 20 = 20. Profit = 20 - 15 = 5. 5 1 Profit % = × 100 = × 100 = 33.33% 15 3 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A vendor buys 200 toys at 150 each. He finds 10% of them broken and sells them at a 40% loss. The rest are sold at a 20% profit. What is his overall profit or loss percentage?`, o: [`12% profit`, `14% profit`, `10% profit`, `15% profit`], e: `Given: Total toys = 200. Broken = 10% = 20 toys. Sold at -40% profit. Good = 90% = 180 toys. Sold at +20% profit. Formula Used: Weighted Average Profit % = (n1 × p1) + (n2 × p2) n + n 1 2 Solution: Since CP is same for all: Overall % = (20 × -40) + (180 × 20) -800 + 3600 200 = 2800200 = 200 = 14%. Overall profit is 14%. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Which of the following numbers cannot be the unit digit of a perfect square?`, o: [`1`, `4`, `8`, `9`], e: `Given: Unit digits of perfect squares. Solution: Possible unit digits of squares: 0, 1, 4, 5, 6, 9. Impossible unit digits: 2, 3, 7, 8. Option C is 8, which cannot be a unit digit. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `If a = 5and b = 5 - 5, which of the following is true?`, o: [`a+b is irrational`, `a-b is rational`, `a× b is rational`, `a+b is rational`], e: `Given: a = 5 b = 5 - 5 Solution: Calculate a + b: a + b = 5 + (5 - 5)= 5. Since 5 is a rational number, a + b is rational. Check other options: a-b= 5 - (5 - 5) = 2 5 - 5(Irrational). ab = 5(5 - 5) = 5 5 - 5(Irrational). Final Answer So the correct answer is (d)` },
  { s: `Quantitative Aptitude`, q: `If the side length of a square is tripled, by what factor does the area increase?`, o: [`3 times`, `6 times`, `9 times`, `27 times`], e: `Given: Side length becomes 3 times the original. Formula Used: Area of Square = side2 Solution: Let original side = s. Original Area A1 = s2. New side = 3s. New Area A2 = (3s)2 = 9s2 Factor of increase = A2 = 9s2 = 9 s2 A1 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `The average monthly salary of 19 employees and 1 manager is 6000. If the manager earns 16000, what is the average(approximate) salary of the employees?`, o: [`5200`, `5473`, `5500`, `5000`], e: `Given: Total people = 20 (19 employees + 1 manager). Combined Average = 6000. Manager's Salary = 16000. Formula Used: Total Sum = Average ×Count Solution: Total Salary of all 20 = 20 × 6000 = 120,000. Total Salary of 19 employees = Total - Manager's Salary = 120,000 - 16,000 = 104,000. Average Salary of Employees = 104, 000 5473.68. 19 Closest integer option is 5473. Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `If sin 2A = cos(A - 45), where 2A is an acute angle, find the value of A.`, o: [`42`, `45`, `24`, `50`], e: `Given: sin 2A = cos(A - 45). Formula Used: sin = cos(90 - ). Solution: cos(90 - 2A) = cos(A - 45) 90 - 2A = A - 45 3A = 135 A = 45 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A trader gains 25% after allowing a discount of 20% on the marked price. If no discount is allowed, what will be his profit percentage?`, o: [`46.25%`, `50%`, `56.25%`, `52.50%`], e: `Given: Gain = 25%. Discount = 20%. Formula Used: Ratio CP : MP = (100 - Discount%) : (100 + Gain%) Solution: CP : MP = (100 - 20) : (100 + 25) = 80 : 125. Let CP = 80, MP = 125. If no discount, SP = MP = 125. Profit = 125 - 80 = 45. 9 45 Profit % = × 100 = × 100 = 56.25%. 80 16 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `If cos = 5/13 and is acute, find the value of sin + cot`, o: [`17/13`, `196/65`, `212/65`, `209/156`], e: `Given: cos = 5/13 Formula Used: Right triangle triplet (5, 12, 13). Base = 5, Hypotenuse = 13, Perpendicular = 12. Solution: s in = 12 13 cot = 5 1212 5 144 + 65 209 Sum = + = = . 13 12 156 156 Final Answer So the correct answer is (d)` },
  { s: `Quantitative Aptitude`, q: `If cos(90 - ) = 4/5, then what is the value of tan ?`, o: [`4/3`, `3/4`, `5/4`, `3/5`], e: `Given: c os(90 - ) = 4/5. Formula Used: c os(90 - ) = sin . tan = sin . cos Solution: s in = 4/5. This corresponds to a 3 - 4 - 5 triangle where Perpendicular = 4, Hypotenuse = 5, Base = 3. Perpendicular 4 t an = = . Base 3 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Simplify: 18 + 50`, o: [`8 2`, `7`, `4 3`, `10`], e: `Given: 18 + 50. Solution: 18 = 9 × 2 = 3 2. 50 = 25 × 2 = 5 2. Sum = 3 2 + 5 2 = 8 2. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `The sum of two numbers is 12 and their product is 32. What is the value of the sum of their squares?`, o: [`80`, `100`, `144`, `64`], e: `Given: a + b = 12. ab = 32. Formula Used: a2 + b2 = (a + b)2 - 2ab Solution: a 2 + b2 = (12)2 - 2(32) = 144 - 64 = 80. Final Answer So the correct answer is (a)` },
  { s: `English Language`, q: `Arrange the parts to form a correct sentence: (1) He entered the meeting link. (2) The audio started breaking. (3) The session had already started. (4) He messaged the coordinator at once.`, o: [`1-3-2-4`, `3-2-1-4`, `1-2-3-4`, `1-3-4-2`], e: `The correct option is (a). To form a meaningful and grammatically correct sequence, we must arrange the events in a logical time order. Sentence (1) should come first because it introduces the initial action: he joined the meeting by entering the link. Sentence (3) logically follows because after joining, he realizes the session had already started. This is a natural observation immediately after entering. Sentence (2) comes next because during an ongoing session, a technical issue (audio breaking) can occur after joining. Sentence (4) must be the last because the message to the coordinator is a reaction to the problem (audio breaking) and the urgent situation. Thus, the coherent sentence flow is: joining the meeting, noticing it has started, facing audio issues, and then informing the coo` },
  { s: `English Language`, q: `Choose the option that completes the sentence using the correct spelling. The ______ silence in the room made everyone uneasy.`, o: [`ominous`, `ominus`, `omineous`, `omminous`], e: `The correct option is (a). Option (A) is the correctly spelt word. Correct spelling is: "ominous". It means giving the impression that something bad or unpleasant is going to happen; threatening or menacing in nature (Hindi meaning: / ). It is commonly used for situations, signs, or feelings that create fear or anxiety about the future. Example: The ominous silence before the announcement worried everyone in the hall. Meanings of all the given options: Option A: Ominous ­ suggesting future trouble or danger (/ ). Option B: Ominus ­ not a standard English spelling; incorrect form ( ). Option C: Omineous ­ incorrect spelling; not acceptable in standard English ( ). Option D: Omminous ­ incorrect spelling due to double \`m'; non-standard form ( ). So the correct answer is (a)` },
  { s: `English Language`, q: `Choose the most suitable option to replace the highlighted part of the sentence. If the sentence is already correct, select \`No substitution required'. In spite the severe cold, they continued the expedition.`, o: [`Despite of`, `Despite the`, `Because of`, `No substitution required`], e: `The correct option is (b). Explanation: The phrase "in spite" must be followed by "of" when it is used before a noun or a noun phrase. Therefore, "In spite the severe cold" is grammatically incorrect because it omits "of". The correct alternatives are either "in spite of the severe cold" or "despite the severe cold". Since the highlighted portion is "In spite the", the best substitution is "Despite the", which makes the sentence correct and concise. Grammatical rule used: "In spite of" and "despite" are used to show contrast (concession). "In spite" requires "of" before a noun/pronoun, but "despite" is directly followed by a noun/pronoun without "of". Example: Despite the heavy rain, the match continued. Information booster: Avoid using "despite of" in standard English. Although it is some` },
  { s: `English Language`, q: `Choose the synonym of the word \`Substantial'.`, o: [`Flimsy`, `Trivial`, `Significant`, `Feeble`], e: `The correct option is (c). The correct synonym of the given word is (c) Significant. Substantial: It means large in amount, value, or importance; considerable and real rather than imaginary (Hindi meaning: / / ). It is used for something that has weight, importance, or a largeCoqpuyarnigtihtyt.© 2026 Adda247 Example: The company made substantial profits this year. Significant: It means important, meaningful, or noticeable; having a considerable effect or meaning (Hindi meaning: / ). It matches "substantial" in the sense of importance and considerable amount. Example: There was a significant improvement in his performance. Synonyms: considerable, important, meaningful, noteworthy. Antonyms: insignificant, trivial, minor, negligible. Meanings of all the other given options: Option A: Flimsy ` },
  { s: `English Language`, q: `A sentence is provided in direct speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding indirect speech. He said, "I have finished my assignment."`, o: [`He said that he had finished his assignment.`, `He said that he has finished his assignment.`, `He said that he finished his assignment.`, `He said he finishes his assignment.`], e: `The correct option is (a). To convert direct to indirect speech, we must change the reporting structure and apply tense backshift when the reporting verb is in the past ("said"). The direct sentence uses Present Perfect tense: "I have finished". In indirect speech, Present Perfect generally changes to Past Perfect when the reporting verb is in the past. Rule-based changes applied: Reporting verb: "said" remains "said" (no question or request here). Conjunction: Use "that" to join the reported clause. Pronoun change: "I" changes to "he" because the speaker is "He". Tense backshift: "have finished" (Present Perfect) changes to "had finished" (Past Perfect). Possessive change: "my" changes to "his" to match the subject "he". Therefore, the correct indirect form is: "He said that he had finish` },
  { s: `English Language`, q: `Change the following from active to passive: He placed the parcel in the wooden box beside the entrance.`, o: [`The parcel had been placed in the wooden box by him beside the entrance.`, `The parcel was placed in the wooden box by him beside the entrance.`, `The wooden box was placed with the parcel by him beside the entrance.`, `The parcel is being placed in the wooden box beside the entrance by him.`], e: `The correct option is (b). To convert an active sentence into passive voice, we make the object of the active sentence the subject of the passive sentence and use the appropriate form of "be" + past participle (V3). The given active sentence is in Simple Past tense: "He placed the parcel". Structure used: Active voice: Subject + V2 + Object + other words. Passive voice: Object (as Subject) + was/were + V3 + by + Subject + other words. Step-by-step conversion: Object in active: "the parcel" becomes the subject in passive. Verb "placed" (V2) becomes "was placed" (was + V3) because the tense is Simple Past and the new subject "parcel" is singular. Agent "He" becomes "by him". Place phrases "in the wooden box beside the entrance" remain unchanged and are placed appropriately after the verb phr` },
  { s: `English Language`, q: `Fill in the blank with an appropriate article. We finally visited ______ Himalayas during our vacation.`, o: [`a`, `an`, `the`, `much`], e: `The correct option is (c). The correct option to fill in the blank is (c) the. Explanation: Names of mountain ranges are treated as plural proper nouns and generally take the definite article "the" (for example, the Alps, the Andes, the Himalayas). Since "Himalayas" refers to a specific and well-known mountain range, we use "the" to indicate definiteness. Example: They trekked in the Himalayas last winter. Why other options are incorrect: Option A: "a" is used with singular countable nouns; "Himalayas" is a plural proper noun range, so "a" is not suitable. Option B: "an" is also for singular countable nouns beginning with a vowel sound; not applicable here. Option D: "much" is a quantifier used with uncountable nouns; it cannot function as an article before a proper noun. Information boost` },
  { s: `English Language`, q: `What is the active voice of the following sentence? When was the monument built by the emperor and later it was restored by the council?`, o: [`When was the emperor built the monument and later they had restored it by the council?`, `When the emperor builds the monument and later who restored it by the council?`, `When did the emperor build the monument and later the council restored it?`, `When the emperor built the monument and later he were restored it by the council?`], e: `The correct option is (c). To convert from passive to active voice, we make the agent (introduced by "by") the subject, change the verb into the correct tense, and keep the object as the receiver of action. The sentence contains two passive clauses joined by "and later". Structure used: Passive voice: Object + was/were + V3 + by + Subject. Active voice: Subject + V2 + Object. Step-by-step conversion: First clause: "the monument built by the emperor" becomes "the emperor built the monument". Since the question is in past, "When was ... built?" becomes "When did ... build?" Second clause: "it was restored by the council" becomes "the council restored it". Maintain sequence: "and later" remains to show the second action happened afterwards. Thus, the correct active form is: "When did the empe` },
  { s: `English Language`, q: `Identify the word in this sentence that contains an error. He dived in the lake with his shoes on.`, o: [`shoes`, `lake`, `dived`, `in`], e: `The correct option is (d). Option (d) contains an error. Detailed explanation of error: The verb "dive" is normally followed by the preposition "into" when we mean entering water from outside by jumping or plunging. The sentence describes the action of entering the lake, so the correct expression is "dived into the lake", not "dived in the lake". "In the lake" would describe a location (already inside the lake), whereas "into the lake" describes movement from outside to inside. Correct sentence: He dived into the lake with his shoes on. Grammatical rule used: Use "into" for movement towards the inside of something; use "in" for position/location inside something. Example: The child jumped into the pool. (movement) / The child is in the pool. (location) Information booster: Similar movement` },
  { s: `English Language`, q: `The coach asked us to draw a straight ___ under the heading.`, o: [`lain`, `line`, `lynn`, `lane`], e: `The correct option is (b). The correct option to fill in the blank is (b) line. Explanation: The phrase "draw a straight line" is a fixed and commonly used expression. "Line" refers to a long, narrow mark or stroke drawn on a surface (Hindi meaning: ). It fits the context of making a straight mark under a heading. Example: Please draw a straight line under the title. Why other options are incorrect: Option A: Lain ­ past participle of "lie" (to recline); it does not mean a drawn mark ( ). Option C: Lynn ­ typically a proper noun/name; not a suitable common noun here ( / ). Option D: Lane ­ a narrow road or path; unrelated to drawing under a heading ( / ). So the correct answer is (b)` },
  { s: `English Language`, q: `A sentence is provided in indirect speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding direct speech. They said that they were playing chess.`, o: [`They said, "We are playing chess."`, `They said, "They are playing chess."`, `They said, "We had played chess."`, `They said, "We were playing chess."`], e: `The correct option is (a). To convert indirect speech to direct speech, we restore the original words of the speaker using quotation marks and adjust pronouns and tense appropriately. In indirect speech, "were playing" is Past Continuous. This form often appears because of backshift from Present Continuous ("are playing") when the reporting verb is in the past ("said"). Therefore, the most accurate direct speech generally restores the tense to Present Continuous. Rule-based changes applied: Remove the conjunction "that". Use quotation marks to present the exact spoken words. Pronoun adjustment: "they" (reported) becomes "we" in direct speech because the original speakers referred to themselves. Tense restoration: "were playing" in reported speech can correspond to "are playing" in direct s` },
  { s: `English Language`, q: `Rearrange the parts of the sentence in the correct order. Digital safety tools P. in online banking systems Q. help secure personal information R. from identity theft S. during cashless transactions`, o: [`SRPQ`, `RSPQ`, `PSQR`, `QSRP`], e: `The correct option is (d). Option (d) is the correct order of the given parts. To form a complete and meaningful sentence, we first need the main verb phrase after the subject "Digital safety tools". The clause "help secure personal information" (Q) provides the core meaning and must come immediately after the subject. Next, we add the context of when this securing happens: "during cashless transactions" (S). Then we specify what the protection is against: "from identity theft" (R). Finally, we mention the domain/setting where these tools operate: "in online banking systems" (P). Subject: Digital safety tools Main verb + object: help secure personal information (Q) Time/condition phrase: during cashless transactions (S) Protection target: from identity theft (R) Place/domain phrase: in onl` },
  { s: `English Language`, q: `Rearrange the parts of the sentence in the correct order. The stock market P. across the country Q. fell sharply R. due to rumours S. amid economic uncertainty`, o: [`SQPR`, `PSQR`, `QSRP`, `RSPQ`], e: `The correct option is (c). Option (c) is the correct order of the given parts. The subject is "The stock market". Immediately after the subject, the main verb phrase should come to complete the sentence's core meaning: "fell sharply" (Q). Then, we add the surrounding situation/condition: "amid economic uncertainty" (S), which explains the broader context. After that, "due to rumours" (R) gives a direct reason contributing to the fall. Finally, "across the country" (P) functions as a place/extent phrase showing the impact was widespread. Subject: The stock market Main action: fell sharply (Q) Context: amid economic uncertainty (S) Cause: due to rumours (R) Extent/place: across the country (P) Thus, the correct sequence is QSRP. So the correct answer is (c)` },
  { s: `English Language`, q: `Choose the option that completes the sentence using the correct spelling. Doctors often treat two types of ______: viral and bacterial.`, o: [`pnemonia`, `pneumonia`, `pnumonia`, `pneumonea`], e: `The correct option is (b). Option (B) is the correctly spelt word. Correct spelling is: "pneumonia". It is an infection that inflames the air sacs in one or both lungs, which may fill with fluid, causing cough, fever, and difficulty in breathing (Hindi meaning: ). It can be caused by bacteria, viruses, or fungi, and hence "viral and bacterial" are valid classifications. Example: The doctor diagnosed him with pneumonia and prescribed medicines. Meanings of all the given options: Option A: Pnemonia ­ incorrect spelling; missing the correct "pneu-" sequence ( ). Option B: Pneumonia ­ lung infection/inflammation of air sacs ( ). Option C: Pnumonia ­ incorrect spelling; missing "eu" after "pn" ( ). Option D: Pneumonea ­ incorrect spelling; wrong ending "-nea" instead of "-nia" ( ). So the corre` },
  { s: `English Language`, q: `Choose the best one-word substitute for: "a collection of aircraft."`, o: [`Squadron`, `Crowd`, `Cluster`, `Pack`], e: `The correct option is (a). The correct option is (a) Squadron. The word "squadron" refers to an organized group or unit of aircraft, especially in the air force; it is a standard collective term used for aircraft in military or aviation contexts (Hindi meaning: - / ). It precisely matches the idea of "a collection of aircraft" as a formal group. Example: A squadron of fighter jets flew over the city during the parade. Meanings of the given other options: Option B: Crowd ­ a large number of people gathered together (). Option C: Cluster ­ a group of similar things close together, often used for objects like stars, grapes, or flowers (/). Option D: Pack ­ a group of animals (especially wolves/dogs) or a bundle of items (/). So the correct answer is (a)` },
  { s: `English Language`, q: `Arrange the parts to form a correct sentence: (1) The wind rose sharply. (2) Leaves began swirling across the road. (3) The sky turned grey within minutes. (4) I shut the doors tightly.`, o: [`1-2-3-4`, `1-4-3-2`, `2-1-3-4`, `1-2-4-3`], e: `The correct option is (a). Option (a) is the correct order of the given sentences because it presents a natural sequence of events during a sudden weather change. (1) "The wind rose sharply" should come first as it is the primary cause that triggers the other visible effects. (2) Due to strong wind, "Leaves began swirling across the road" logically follows as an immediate consequence. (3) "The sky turned grey within minutes" then indicates the worsening weather condition, building towards a storm-like situation. (4) Finally, the speaker reacts to the threatening environment: "I shut the doors tightly," which is a protective action that fits best at the end. The sequence shows cause effect further development human response, making it coherent and meaningful. So the correct answer is (a)` },
  { s: `English Language`, q: `What does the idiom "Barking up the wrong tree" mean?`, o: [`Accusing the wrong person`, `Solving a problem quickly`, `Refusing to accept facts`, `Taking a risky shortcut`], e: `The correct option is (a). Option (a) is the correct meaning of the given idiom. Barking up the wrong tree: This idiom means to make a wrong assumption about someone or something; to blame or accuse the wrong person or to pursue a mistaken course of action (Hindi idiom meaning: / ). It suggests that one is looking in the wrong place for the answer or culprit. Example: If you think I broke the vase, you are barking up the wrong tree; I was not even at home. Other related idioms and their meanings: Jumping to conclusions ­ forming an opinion without sufficient evidence. Miss the mark ­ to be incorrect or fail to achieve the intended result. On the wrong track ­ following an incorrect plan or idea. Point the finger at ­ to blame someone (sometimes incorrectly). So the correct answer is (a)` },
  { s: `English Language`, q: `Convert the following indirect sentence into direct speech. Choose the most accurate option. The player exclaimed with delight that he had scored the winning goal.`, o: [`The player said, "I have scored the winning goal!"`, `The player exclaimed, "I have scored the winning goal!"`, `The player said, "Alas! I have scored the winning goal!"`, `The player shouted, "Scoring the winning goal!"`], e: `The correct option is (b). To convert indirect to direct speech, we restore the exact words within quotation marks and choose the correct reporting verb based on the mood/emotion. The sentence says "exclaimed with delight", which indicates a joyful exclamation. Therefore, we must use "exclaimed" in direct speech. Also, the reported clause uses Past Perfect "had scored", which is typically a backshift from Present Perfect "have scored" in direct speech. Rule-based conversion: Remove the conjunction "that". Use quotation marks for the spoken words. Change pronoun: "he" becomes "I" because the player is speaking about himself. Tense restoration: "had scored" becomes "have scored" in direct speech (common backshift reversal). Use an exclamation mark to reflect "delight". Thus, the best direct ` },
  { s: `English Language`, q: `Choose the option which best completes the sentence. When her son failed to return from the camp with the other boys, Mrs Sharma was ____, fearing something terrible had happened.`, o: [`at her wits' end`, `on cloud nine`, `in seventh heaven`, `on the same page`], e: `The correct option is (a). The correct option to fill in the blank is (a) at her wits' end. Explanation: "At one's wits' end" means being extremely worried, confused, or distressed and not knowing what to do next (Hindi meaning: / , ). In the sentence, Mrs Sharma fears something terrible, which clearly indicates anxiety and helplessness. Therefore, this idiomatic expression fits perfectly. Example: After searching for hours without any clue, she was at her wits' end. Why other options are incorrect: Option B: On cloud nine ­ extremely happy ( ); opposite of the worried context. Option C: In seventh heaven ­ extremely delighted ( ); does not match fear and anxiety. Option D: On the same page ­ in agreement or understanding ( ); not related to distress. So the correct answer is (a)` },
  { s: `English Language`, q: `Which of the given options is the most logical sequencing of the following sentences to form a meaningful paragraph? 1. Therefore, we must adopt sustainable practices immediately. 2. Climate change poses a grave danger to the earth. 3. Rising heat intensifies droughts, floods, and storms. 4. Human actions like pollution and deforestation fuel it.`, o: [`1-2-4-3`, `4-3-2-1`, `2-4-3-1`, `3-2-1-4`], e: `The correct option is (c). The correct sequence is 2-4-3-1. Explanation of the correct sequence of each sentence: Sentence 2 introduces the topic and gives the main idea: climate change is a serious danger. A paragraph should start with a clear theme statement. Sentence 4 logically follows because it explains the cause of climate change by stating that human actions fuel it. After introducing a problem, we typically explain its reasons. Sentence 3 then provides the effects/impacts of climate change, describing how rising heat worsens droughts, floods, and storms. This develops the paragraph with consequences. Sentence 1 concludes with a result and call to action using "Therefore", which must come after causes and effects have been stated. It provides the logical conclusion of the paragraph` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The complaint letters that were received through email (1)/ and verified by the clerk (2)/ are being files systematically (3)/ in separate folders. (4)`, o: [`The complaint letters that were received through email (1)`, `and verified by the clerk (2)`, `are being files systematically (3)`, `in separate folders (4)`], e: `The correct option is (c). Option (c) contains an error. Detailed explanation of error: The phrase "are being files" is grammatically incorrect because after "are being" (present continuous passive structure), we must use the past participle (V3) form of the main verb. The verb intended here is "file" (to arrange documents in folders). The correct past participle is "filed", not "files". Hence, the correct phrase should be "are being filed systematically". Correct sentence: The complaint letters that were received through email and verified by the clerk are being filed systematically in separate folders. Grammatical rule used: Present Continuous Passive = am/is/are + being + V3. Example: The reports are being checked by the manager. Information booster: In passive voice, always ensure the ` },
  { s: `English Language`, q: `Rearrange the parts of the sentence in the correct order. Industrial expansion P. weakens heritage Q. in old city quarters R. and traffic overcrowding S. by cultural erosion`, o: [`QRPS`, `PSRQ`, `QSPR`, `RQPS`], e: `The correct option is (d). Option (d) is the correct order of the given parts. The subject is "Industrial expansion", and it is being joined with another subject-like phrase "and traffic overcrowding" (R), forming a compound subject. After stating the setting "in old city quarters" (Q), the sentence must include the main verb and object idea "weakens heritage" (P). Finally, "by cultural erosion" (S) gives the manner/cause through which heritage is weakened. Start with R to add the second linked factor: "and traffic overcrowding". Place Q next to specify the location/setting: "in old city quarters". Then use P to complete the main clause: "weakens heritage". End with S to explain the mechanism: "by cultural erosion". Thus, the correct sequence is RQPS. So the correct answer is (d)` },
  { s: `English Language`, q: `Choose the correct indirect speech form of the following sentence. Ritu said to Neha, "What will you buy for me on my birthday next year?"`, o: [`Ritu asked Neha what she would buy for her on her birthday the following year.`, `Ritu asked Neha what she would buy for her on her birthday the previous year.`, `Ritu asked Neha what she should buy for her on her birthday next year.`, `Ritu requested Neha what she should buy for her on her birthday the coming year.`], e: `The correct option is (a). To change direct to indirect speech for a question, we use the reporting verb "asked" and remove the question form by using statement order (subject + verb). We also apply tense backshift when the reporting verb is in the past ("said"), and we change pronouns and time expressions appropriately. Step-by-step rules applied: Reporting verb change: "said to" becomes "asked" because it is an interrogative sentence. Remove quotation marks and question mark; use indirect question form. Change word order: "What will you buy" becomes "what she would buy" (no auxiliary inversion in indirect questions). Tense backshift: "will" changes to "would" because the reporting verb is in the past. Pronoun changes: "you" (addressing Neha) becomes "she"; "me" (Ritu) becomes "her". Time` },
  { s: `English Language`, q: `Change the following from active to passive: The committee had approved the proposal after a lengthy discussion.`, o: [`The proposal was being approved after a lengthy discussion.`, `The proposal had been approved by the committee after a lengthy discussion.`, `The proposal is approved after a lengthy discussion.`, `The proposal was approved after a lengthy discussion.`], e: `The correct option is (b). To convert active to passive, we make the object the subject and use the appropriate passive verb form. The active sentence is in Past Perfect tense: "had approved". Therefore, the passive must be Past Perfect passive: "had been approved". Structure used: Active voice (Past Perfect): Subject + had + V3 + Object + other words. Passive voice (Past Perfect): Object (as Subject) + had been + V3 + by + Subject + other words. Step-by-step conversion: Object in active: "the proposal" becomes the subject in passive. Verb phrase: "had approved" becomes "had been approved". Agent: "the committee" is added using "by the committee". Remaining phrase: "after a lengthy discussion" stays as it is. Thus, the correct passive sentence is: "The proposal had been approved by the com` },
  { s: `English Language`, q: `Transform the following sentence into active voice. The meals have been prepared carefully by the chef.`, o: [`The chef have prepared the meals carefully.`, `The chef has prepared the meals carefully.`, `The chef has prepared the meals by carefully.`, `The chef has prepared the meal carefully.`], e: `The correct option is (b). To convert passive to active voice, we make the agent (introduced by "by") the subject and change the verb to match the tense. The passive sentence is in Present Perfect passive: "have been prepared". The corresponding active voice is Present Perfect active: "has/have prepared". Structure used: Passive voice (Present Perfect): Object + have/has been + V3 + by + Subject. Active voice (Present Perfect): Subject + have/has + V3 + Object. Step-by-step conversion: Agent: "by the chef" becomes the subject "The chef". Object: "The meals" becomes the object in active voice. Verb: "have been prepared" becomes "has prepared" because "chef" is singular, so we use "has". Adverb: "carefully" remains in the same sense and is placed after the object for clarity. Thus, the corre` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP-HS' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Higher Secondary Level)',
      code: 'SSC-SSP-HS',
      description: 'Staff Selection Commission - Selection Post (Higher Secondary Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Higher Secondary Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Higher Secondary) - 25 July 2025 Shift-2 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Higher Secondary', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '2',
    pyqExamName: 'SSC Selection Post Phase XIII (Higher Secondary) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
